-- 1. Criar departamentos
INSERT INTO core.departamentos \(id, nome, descricao, filial_id, status, created_at, updated_at\)
SELECT gen_random_uuid\(\), 'Tecnologia da Informacao', 'Departamento de TI', f.id, 'ATIVO', NOW\(\), NOW\(\)
