INSERT INTO core.departamentos \(id, nome, descricao, filial_id, status, created_at, updated_at\)
SELECT gen_random_uuid\(\), 'Administrativo', 'Departamento Administrativo', f.id, 'ATIVO', NOW\(\), NOW\(\)
FROM core.filiais f WHERE f.codigo = '01';

INSERT INTO core.departamentos \(id, nome, descricao, filial_id, status, created_at, updated_at\)
SELECT gen_random_uuid\(\), 'Operacoes', 'Departamento de Operacoes', f.id, 'ATIVO', NOW\(\), NOW\(\)
FROM core.filiais f WHERE f.codigo = '01';

-- 2. Atribuir todos os usuarios sem departamento ao depto TI
UPDATE core.usuarios SET departamento_id = \(
  SELECT d.id FROM core.departamentos d WHERE d.nome = 'Tecnologia da Informacao' LIMIT 1
\) WHERE departamento_id IS NULL;

-- 3. Tornar coluna obrigatoria
ALTER TABLE core.usuarios ALTER COLUMN departamento_id SET NOT NULL;

-- Verificar
SELECT nome, departamento_id FROM core.departamentos;
SELECT count\(*\) as usuarios_sem_depto FROM core.usuarios WHERE departamento_id IS NULL;
" 2>&1)

